const payload = $json.body || $json;
const query = String(payload.query || '').trim();
if (!query) throw new Error('query is required');

const constraints = payload.constraints || {};
const options = payload.options || {};

const ledger = {
  session_id: payload.session_id || crypto.randomUUID(),
  started_at: new Date().toISOString(),
  max_context_tokens_per_call: Number(constraints.max_context_tokens_per_call || $env.MAX_CONTEXT_TOKENS_PER_CALL || 2000),
  max_session_cost_usd: Number(constraints.max_session_cost_usd || $env.MAX_SESSION_COST_USD || 0.05),
  max_runtime_seconds: Number(constraints.max_runtime_seconds || $env.MAX_RUNTIME_SECONDS || 480),
  total_tokens: 0,
  total_cost_usd: 0,
  max_context_tokens_seen: 0,
  degrade_mode: false,
  constraint_violations: []
};

return [{
  json: {
    query,
    options: {
      depth: options.depth || 'medium',
      citations_required: options.citations_required !== false
    },
    ledger,
    trace: {
      subquestions_processed: 0,
      evidence_cards_created: 0,
      degrade_mode_triggered: false
    },
    memory: {
      working_memory: [],
      summary_memory: '',
      evidence_cards: []
    }
  }
}];

const data = $json;
const q = data.query;
const depth = data.options.depth;

const sub = [
  'Define the problem space and evaluation criteria for: ' + q,
  'Collect current evidence, benchmarks, and implementation patterns for: ' + q,
  'Synthesize trade-offs, constraints, and recommended approach for: ' + q
];
if (depth === 'high') {
  sub.push('Identify failure modes and mitigation strategies for: ' + q);
  sub.push('Estimate cost, latency, and operational implications for: ' + q);
}

data.query_breakdown = sub;
return [{ json: data }];

const data = $json;
const tavilyApiKey = $env.TAVILY_API_KEY || '';

function estimateTokens(text) { return Math.max(1, Math.ceil(String(text || '').length / 4)); }
function shortId(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) h = ((h << 5) - h) + str.charCodeAt(i);
  return Math.abs(h).toString(16).slice(0, 12);
}
function scoreSourceQuality(url) {
  const d = String(url || '');
  if (d.includes('arxiv.org') || d.includes('github.com') || d.includes('docs.') || d.includes('.gov') || d.includes('.edu')) return 0.9;
  return 0.6;
}
async function tavilySearch(query, topK) {
  if (!tavilyApiKey) {
    return [
      { title: 'Open source deep research patterns', url: 'https://example.com/deep-research-patterns', content: 'Multi-query retrieval and compression improve answer quality while controlling context size.' },
      { title: 'RAG memory architecture', url: 'https://example.com/rag-memory', content: 'Hybrid memory combines short-term working memory with episodic vector storage and summary memory.' },
      { title: 'Cost-aware LLM orchestration', url: 'https://example.com/cost-aware-orchestration', content: 'A budget governor enforces token and dollar limits, using degrade modes before hard stop.' }
    ].slice(0, topK);
  }

  const response = await fetch('https://api.tavily.com/search', {
    method: 'POST',
    headers: {
      Authorization: 'Bearer ' + tavilyApiKey,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      query,
      search_depth: 'advanced',
      max_results: topK,
      include_answer: false,
      include_raw_content: true
    })
  });
  if (!response.ok) throw new Error('Tavily error: ' + response.status);
  const payload = await response.json();
  return payload.results || [];
}

let topK = data.options.depth === 'high' ? 6 : (data.options.depth === 'low' ? 3 : 5);
if (data.ledger.degrade_mode) topK = Math.max(2, topK - 2);

const elapsed = (Date.now() - Date.parse(data.ledger.started_at)) / 1000;
if (elapsed > data.ledger.max_runtime_seconds) {
  data.ledger.constraint_violations.push('runtime exceeded ' + data.ledger.max_runtime_seconds + 's');
  data.ledger.degrade_mode = true;
  data.trace.degrade_mode_triggered = true;
}

const evidenceCards = [];
for (let i = 0; i < data.query_breakdown.length; i++) {
  const sq = data.query_breakdown[i];
  const subId = 'sq-' + (i + 1);
  const variants = [sq, sq + ' best practices', sq + ' trade-offs and benchmarks'];

  let merged = [];
  for (const variant of variants) {
    const projectedIn = estimateTokens(variant);
    const projectedCost = (projectedIn / 1000000) * 0.50;

    if (data.ledger.total_cost_usd + projectedCost > data.ledger.max_session_cost_usd) {
      data.ledger.degrade_mode = true;
      data.trace.degrade_mode_triggered = true;
      data.ledger.constraint_violations.push('degrade-mode: retrieval projected cost over budget');
      break;
    }

    const results = await tavilySearch(variant, topK);
    merged = merged.concat(results);

    data.ledger.total_tokens += projectedIn + Math.min(120, results.length * 30);
    data.ledger.total_cost_usd += projectedCost;
    data.ledger.max_context_tokens_seen = Math.max(data.ledger.max_context_tokens_seen, projectedIn);
  }

  const slice = merged.slice(0, topK);
  for (let j = 0; j < slice.length; j++) {
    const r = slice[j] || {};
    const content = String(r.content || '').trim();
    const title = String(r.title || 'Untitled source').trim();
    const url = String(r.url || 'https://example.com/unknown').trim();
    const claim = String((content.split('.')[0] || ('Finding ' + (j + 1) + ' for ' + sq))).slice(0, 240);

    evidenceCards.push({
      id: shortId(data.ledger.session_id + '|' + subId + '|' + j + '|' + url),
      session_id: data.ledger.session_id,
      subquestion_id: subId,
      claim_candidate: claim,
      supporting_excerpt: content.slice(0, 900),
      source_url: url,
      source_title: title,
      retrieval_score: Math.max(0.2, 1.0 - j * 0.12),
      source_quality: scoreSourceQuality(url),
      recency_score: 0.5,
      novelty_score: Math.max(0.3, 0.9 - j * 0.08),
      estimated_tokens: estimateTokens(claim + '
' + content),
      timestamp: new Date().toISOString()
    });
  }

  data.memory.working_memory.push({
    subquestion_id: subId,
    text: sq,
    card_count: slice.length,
    timestamp: new Date().toISOString()
  });

  data.trace.subquestions_processed += 1;
  data.trace.evidence_cards_created += slice.length;
}

data.memory.evidence_cards = evidenceCards;
return [{ json: data }];

const data = $json;

function estimateTokens(text) { return Math.max(1, Math.ceil(String(text || '').length / 4)); }
function utility(c) {
  return 0.45 * c.retrieval_score + 0.25 * c.novelty_score + 0.20 * c.source_quality + 0.10 * c.recency_score;
}

const cards = data.memory.evidence_cards || [];
for (let i = 0; i < cards.length; i += 2) {
  const window = cards.slice(i, i + 2);
  if (!window.length) continue;
  const fragment = window.map(c => '- [' + c.id + '] ' + c.claim_candidate + ' (src: ' + c.source_title + ')').join('
');
  data.memory.summary_memory = data.memory.summary_memory ? (data.memory.summary_memory + '
' + fragment) : fragment;
}

const plannerTokens = 250;
const summaryTokens = 450;
const evidenceTokens = 1050;
const instructionTokens = 250;
const hardBudget = Math.min(data.ledger.max_context_tokens_per_call, plannerTokens + summaryTokens + evidenceTokens + instructionTokens);

let summary = data.memory.summary_memory || '';
while (estimateTokens(summary) > summaryTokens) summary = summary.slice(Math.floor(summary.length * 0.1));

const sorted = [...cards].sort((a, b) => (utility(b) / Math.max(1, b.estimated_tokens)) - (utility(a) / Math.max(1, a.estimated_tokens)));
const selected = [];
let used = 0;
for (const c of sorted) {
  const t = Math.max(12, c.estimated_tokens || 12);
  if (used + t > evidenceTokens) continue;
  selected.push(c);
  used += t;
}

let total = estimateTokens(JSON.stringify(data.memory.working_memory)) + estimateTokens(summary) + used + instructionTokens;
while (total > hardBudget && selected.length) {
  selected.sort((a, b) => utility(a) - utility(b));
  const removed = selected.shift();
  used -= Math.max(12, removed.estimated_tokens || 12);
  total = estimateTokens(JSON.stringify(data.memory.working_memory)) + estimateTokens(summary) + used + instructionTokens;
}

data.memory.summary_memory = summary;
data.memory.selected_evidence_cards = selected;
data.memory.estimated_context_tokens = total;

if (data.memory.estimated_context_tokens > data.ledger.max_context_tokens_per_call) {
  data.ledger.degrade_mode = true;
  data.trace.degrade_mode_triggered = true;
  data.ledger.constraint_violations.push('degrade-mode: context tokens exceed hard limit');
}
if (data.ledger.total_cost_usd > data.ledger.max_session_cost_usd) {
  data.ledger.degrade_mode = true;
  data.trace.degrade_mode_triggered = true;
  data.ledger.constraint_violations.push('degrade-mode: cost exceeded hard limit');
}

return [{ json: data }];

const data = $json;
const openaiKey = $env.OPENAI_API_KEY || '';
const model = $env.MODEL_RESEARCH || 'gpt-4.1';

function estimateTokens(text) { return Math.max(1, Math.ceil(String(text || '').length / 4)); }

function offlineSynthesis(cards, citationsRequired) {
  const findings = cards.slice(0, 8).map(c => '- ' + c.claim_candidate + (citationsRequired ? ' [' + c.id + ']' : ''));
  const citations = cards.slice(0, 8).map(c => '- [' + c.id + '] ' + c.source_title + ': ' + c.source_url);
  return [
    '## Evidence-backed Findings',
    ...(findings.length ? findings : ['- No high-confidence findings were produced within current budget constraints.']),
    '',
    '## Caveats and Unknowns',
    '- Evidence quality varies by source domain and recency.',
    '- Budget-constrained retrieval may miss niche primary sources.',
    '',
    '## Citations',
    ...citations
  ].join('
');
}

const cards = data.memory.selected_evidence_cards || [];
const prompt = [
  'You are a deep research synthesis assistant.',
  'Query: ' + data.query,
  'Subquestions: ' + JSON.stringify(data.query_breakdown || []),
  'Summary Memory: ' + (data.memory.summary_memory || ''),
  'Evidence: ' + JSON.stringify(cards)
].join('

');

const projectedInput = estimateTokens(prompt);
if (projectedInput > data.ledger.max_context_tokens_per_call) {
  data.ledger.degrade_mode = true;
  data.trace.degrade_mode_triggered = true;
  data.ledger.constraint_violations.push('final-synthesis: context exceeds hard limit');
}

let answer = offlineSynthesis(cards, data.options.citations_required);

if (openaiKey && !data.ledger.degrade_mode) {
  const response = await fetch('https://api.openai.com/v1/responses', {
    method: 'POST',
    headers: {
      Authorization: 'Bearer ' + openaiKey,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model,
      input: prompt,
      max_output_tokens: 900
    })
  });

  if (response.ok) {
    const payload = await response.json();
    const output = payload.output || [];
    const parts = [];
    for (const item of output) {
      const content = item.content || [];
      for (const c of content) {
        if (c.type === 'output_text') parts.push(c.text || '');
      }
    }
    if (parts.length) answer = parts.join('
').trim();
  }
}

const outTokens = estimateTokens(answer);
data.ledger.total_tokens += projectedInput + outTokens;
data.ledger.total_cost_usd += (projectedInput / 1000000) * 2.0 + (outTokens / 1000000) * 8.0;
data.ledger.max_context_tokens_seen = Math.max(data.ledger.max_context_tokens_seen, projectedInput);

data.answer_markdown = answer;
return [{ json: data }];

const data = $json;

const claimMatches = [...String(data.answer_markdown || '').matchAll(/\[([a-f0-9]{6,12})\]/g)].map(m => m[1]);
const known = new Set((data.memory.selected_evidence_cards || []).map(c => c.id));
const supported = claimMatches.filter(id => known.has(id));
const unsupported = claimMatches.filter(id => !known.has(id));
if (unsupported.length) data.ledger.constraint_violations.push('verification: unsupported claim ids detected');

const citations = (data.memory.selected_evidence_cards || []).slice(0, 20).map(c => ({
  claim_id: c.id,
  url: c.source_url,
  title: c.source_title,
  confidence: Math.min(1, Math.max(0.2, c.retrieval_score || 0.2))
}));

const response = {
  answer_markdown: data.answer_markdown,
  citations,
  query_breakdown: data.query_breakdown || [],
  budget_report: {
    total_tokens: data.ledger.total_tokens,
    total_cost_usd: Number(data.ledger.total_cost_usd.toFixed(6)),
    max_context_tokens_seen: data.ledger.max_context_tokens_seen,
    constraint_violations: data.ledger.constraint_violations
  },
  trace: data.trace
};

return [{ json: response }];
